import 'package:flutter/foundation.dart';

enum PaymentMethod {
  creditCard,
  debitCard,
  applePay,
  googlePay,
  inAppPurchase,
}

enum PaymentStatus {
  pending,
  processing,
  completed,
  failed,
  cancelled,
  refunded,
  requiresAction,
  requiresConfirmation,
}

enum TransactionType {
  purchase,
  subscription,
  refund,
  preAuthorization,
}

enum CardNetwork {
  visa,
  mastercard,
  amex,
  discover,
  unknown,
}

@immutable
class PaymentAmount {
  final int amountInCents;
  final String currency;

  const PaymentAmount({
    required this.amountInCents,
    this.currency = 'USD',
  });

  double get amountInDollars => amountInCents / 100.0;

  String get displayAmount {
    final symbol = _currencySymbols[currency.toUpperCase()] ?? currency;
    return '$symbol${amountInDollars.toStringAsFixed(2)}';
  }

  static const _currencySymbols = {
    'USD': '\$',
    'EUR': '€',
    'GBP': '£',
    'JPY': '¥',
    'CAD': 'CA\$',
    'AUD': 'A\$',
  };

  Map<String, dynamic> toJson() => {
        'amount': amountInCents,
        'currency': currency,
      };

  factory PaymentAmount.fromJson(Map<String, dynamic> json) {
    return PaymentAmount(
      amountInCents: json['amount'] as int,
      currency: json['currency'] as String? ?? 'USD',
    );
  }
}

@immutable
class PaymentCard {
  final String tokenizedId;
  final CardNetwork network;
  final String last4;
  final int expiryMonth;
  final int expiryYear;
  final String? cardholderName;
  final String? fingerprint;

  const PaymentCard({
    required this.tokenizedId,
    required this.network,
    required this.last4,
    required this.expiryMonth,
    required this.expiryYear,
    this.cardholderName,
    this.fingerprint,
  });

  bool get isExpired {
    final now = DateTime.now();
    return DateTime(expiryYear, expiryMonth + 1).isBefore(now);
  }

  String get displayNumber => '•••• •••• •••• $last4';

  String get displayExpiry =>
      '${expiryMonth.toString().padLeft(2, '0')}/${expiryYear.toString().substring(2)}';

  Map<String, dynamic> toJson() => {
        'tokenized_id': tokenizedId,
        'network': network.name,
        'last4': last4,
        'expiry_month': expiryMonth,
        'expiry_year': expiryYear,
        'cardholder_name': cardholderName,
      };

  factory PaymentCard.fromJson(Map<String, dynamic> json) {
    return PaymentCard(
      tokenizedId: json['tokenized_id'] as String,
      network: CardNetwork.values.firstWhere(
        (n) => n.name == json['network'],
        orElse: () => CardNetwork.unknown,
      ),
      last4: json['last4'] as String,
      expiryMonth: json['expiry_month'] as int,
      expiryYear: json['expiry_year'] as int,
      cardholderName: json['cardholder_name'] as String?,
      fingerprint: json['fingerprint'] as String?,
    );
  }
}

