import 'dart:convert';
import 'dart:math';
import 'dart:typed_data';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:crypto/crypto.dart';
import '../models/payment_models.dart';

class SecureStorageService {
  static const _keyPrefix = 'pmt_';
  static const _savedCardsKey = '${_keyPrefix}saved_cards';
  static const _transactionLogKey = '${_keyPrefix}tx_log';
  static const _deviceFingerprintKey = '${_keyPrefix}device_fp';
  static const _sessionTokenKey = '${_keyPrefix}session';

  final FlutterSecureStorage _storage;

  SecureStorageService({FlutterSecureStorage? storage})
      : _storage = storage ??
            const FlutterSecureStorage(
              aOptions: AndroidOptions(
                encryptedSharedPreferences: true,
                keyCipherAlgorithm: KeyCipherAlgorithm.RSA_ECB_OAEPwithSHA_256andMGF1Padding,
                storageCipherAlgorithm: StorageCipherAlgorithm.AES_GCM_NoPadding,
              ),
              iOptions: IOSOptions(
                accessibility: KeychainAccessibility.first_unlock_this_device,
                accountName: 'payment_module',
              ),
            );

  // Generate cryptographically secure idempotency key
  String generateIdempotencyKey() {
    final random = Random.secure();
    final bytes = Uint8List(32);
    for (var i = 0; i < bytes.length; i++) {
      bytes[i] = random.nextInt(256);
    }
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final combined = '$timestamp-${base64Url.encode(bytes)}';
    return sha256.convert(utf8.encode(combined)).toString();
  }

  // Save tokenized card securely
  Future<void> saveCard(PaymentCard card) async {
    final cards = await getSavedCards();
    // Remove duplicate by fingerprint or last4+network
    cards.removeWhere((c) =>
        c.fingerprint == card.fingerprint ||
        (c.last4 == card.last4 && c.network == card.network));
    cards.add(card);

    final jsonList = cards.map((c) => c.toJson()).toList();
    await _storage.write(
      key: _savedCardsKey,
      value: jsonEncode(jsonList),
    );
  }

  Future<List<PaymentCard>> getSavedCards() async {
    final data = await _storage.read(key: _savedCardsKey);
    if (data == null) return [];

    try {
      final jsonList = jsonDecode(data) as List;
      return jsonList
          .map((j) => PaymentCard.fromJson(j as Map<String, dynamic>))
          .where((card) => !card.isExpired)
          .toList();
    } catch (_) {
      return [];
    }
  }

  Future<void> removeCard(String tokenizedId) async {
    final cards = await getSavedCards();
    cards.removeWhere((c) => c.tokenizedId == tokenizedId);
    final jsonList = cards.map((c) => c.toJson()).toList();
    await _storage.write(
      key: _savedCardsKey,
      value: jsonEncode(jsonList),
    );
  }

  // Transaction audit log
  Future<void> logTransaction(PaymentResult result) async {
    final logs = await _getTransactionLogs();
    logs.add({
      'transaction_id': result.transactionId,
      'status': result.status.name,
      'amount': result.amount.toJson(),
      'method': result.method.name,
      'timestamp': result.timestamp.toIso8601String(),
      'error_code': result.errorCode,
    });

    // Keep only last 100 transactions
    if (logs.length > 100) {
      logs.removeRange(0, logs.length - 100);
    }

    await _storage.write(
      key: _transactionLogKey,
      value: jsonEncode(logs),
    );
  }

  Future<List<Map<String, dynamic>>> _getTransactionLogs() async {
    final data = await _storage.read(key: _transactionLogKey);
    if (data == null) return [];
    try {
      return (jsonDecode(data) as List).cast<Map<String, dynamic>>();
    } catch (_) {
      return [];
    }
  }

  Future<void> saveSessionToken(String token) async {
    await _storage.write(key: _sessionTokenKey, value: token);
  }

  Future<String?> getSessionToken() async {
    return _storage.read(key: _sessionTokenKey);
  }

  Future<void> saveDeviceFingerprint(String fingerprint) async {
    await _storage.write(key: _deviceFingerprintKey, value: fingerprint);
  }

  Future<String?> getDeviceFingerprint() async {
    return _storage.read(key: _deviceFingerprintKey);
  }

  Future<void> clearAll() async {
    await _storage.deleteAll();
  }

  Future<void> clearSession() async {
    await _storage.delete(key: _sessionTokenKey);
  }

  // Compute HMAC for request signing
  String computeHmac(String data, String secret) {
    final key = utf8.encode(secret);
    final bytes = utf8.encode(data);
    final hmacSha256 = Hmac(sha256, key);
    return hmacSha256.convert(bytes).toString();
  }
}

