import 'dart:io';
import 'package:flutter/foundation.dart';
import 'package:flutter/services.dart';
import '../models/payment_models.dart';

class DeviceIntegrityService {
  static const _channel = MethodChannel('com.app.payment/device_integrity');

  // Comprehensive device integrity check
  Future<DeviceIntegrityResult> checkIntegrity() async {
    final checks = await Future.wait([
      _checkRoot(),
      _checkEmulator(),
      _checkDebugger(),
      _checkTampering(),
      _performAttestation(),
    ]);

    final isRooted = checks[0] as bool;
    final isEmulator = checks[1] as bool;
    final isDebuggerAttached = checks[2] as bool;
    final isTampered = checks[3] as bool;
    final attestationToken = checks[4] as String?;

    final isValid = !isRooted && !isEmulator && !isDebuggerAttached && !isTampered;

    return DeviceIntegrityResult(
      isIntegrityValid: isValid,
      isRooted: isRooted,
      isEmulator: isEmulator,
      isDebuggerAttached: isDebuggerAttached,
      isTampered: isTampered,
      attestationToken: attestationToken,
      checkedAt: DateTime.now(),
      details: {
        'platform': Platform.operatingSystem,
        'version': Platform.operatingSystemVersion,
        'is_debug': kDebugMode,
      },
    );
  }

  Future<bool> _checkRoot() async {
    try {
      if (Platform.isAndroid) {
        return await _checkAndroidRoot();
      } else if (Platform.isIOS) {
        return await _checkiOSJailbreak();
      }
      return false;
    } catch (_) {
      // Fail secure - assume compromised if check fails
      return true;
    }
  }

  Future<bool> _checkAndroidRoot() async {
    try {
      final result = await _channel.invokeMethod<bool>('checkRoot');
      return result ?? true;
    } on MissingPluginException {
      // Fallback: check common root indicators
      final rootIndicators = [
        '/system/app/Superuser.apk',
        '/sbin/su',
        '/system/bin/su',
        '/system/xbin/su',
        '/data/local/xbin/su',
        '/data/local/bin/su',
        '/system/sd/xbin/su',
        '/system/bin/failsafe/su',
        '/data/local/su',
        '/su/bin/su',
      ];

      for (final path in rootIndicators) {
        if (await File(path).exists()) return true;
      }
      return false;
    }
  }

  Future<bool> _checkiOSJailbreak() async {
    try {
      final result = await _channel.invokeMethod<bool>('checkJailbreak');
      return result ?? true;
    } on MissingPluginException {
      final jailbreakIndicators = [
        '/Applications/Cydia.app',
        '/Library/MobileSubstrate/MobileSubstrate.dylib',
        '/bin/bash',
        '/usr/sbin/sshd',
        '/etc/apt',
        '/private/var/lib/apt/',
        '/usr/bin/ssh',
      ];

      for (final path in jailbreakIndicators) {
        if (await File(path).exists()) return true;
      }
      return false;
    }
  }

  Future<bool> _checkEmulator() async {
    try {
      final result = await _channel.invokeMethod<bool>('checkEmulator');
      return result ?? false;
    } on MissingPluginException {
      if (Platform.isAndroid) {
        // Check common emulator properties
        final emulatorIndicators = [
          'goldfish',
          'ranchu',
          'sdk_gphone',
          'emulator',
          'simulator',
        ];
        final model = Platform.localHostname.toLowerCase();
        return emulatorIndicators.any((i) => model.contains(i));
      }
      return false;
    }
  }

  Future<bool> _checkDebugger() async {
    if (kDebugMode) return true;

    try {
      final result = await _channel.invokeMethod<bool>('checkDebugger');
      return result ?? false;
    } on MissingPluginException {
      return kDebugMode;
    }
  }

  Future<bool> _checkTampering() async {
    try {
      final result = await _channel.invokeMethod<bool>('checkTampering');
      return result ?? false;
    } on MissingPluginException {
      return false;
    }
  }

  Future<String?> _performAttestation() async {
    try {
      if (Platform.isAndroid) {
        return await _channel.invokeMethod<String>('getPlayIntegrityToken');
      } else if (Platform.isIOS) {
        return await _channel.invokeMethod<String>('getAppAttestToken');
      }
      return null;
    } catch (_) {
      return null;
    }
  }

  // Check if device has secure screen lock
  Future<bool> hasSecureScreenLock() async {
    try {
      final result = await _channel.invokeMethod<bool>('hasSecureScreenLock');
      return result ?? false;
    } catch (_) {
      return false;
    }
  }

  // Generate device fingerprint for fraud detection
  Future<String> generateDeviceFingerprint() async {
    try {
      final result = await _channel.invokeMethod<String>('getDeviceFingerprint');
      return result ?? 'unknown';
    } catch (_) {
      return 'unknown';
    }
  }
}

