import 'dart:async';
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;
import 'package:http/io_client.dart';
import '../config/payment_config.dart';
import '../models/payment_models.dart';
import 'secure_storage_service.dart';

class PaymentGatewayService {
  final PaymentConfig config;
  final SecureStorageService _secureStorage;
  late final http.Client _httpClient;

  PaymentGatewayService({
    required this.config,
    required SecureStorageService secureStorage,
  }) : _secureStorage = secureStorage {
    _httpClient = _createSecureClient();
  }

  http.Client _createSecureClient() {
    if (!config.enableCertificatePinning) {
      return http.Client();
    }

    final httpClient = HttpClient()
      ..connectionTimeout = Duration(seconds: config.transactionTimeoutSeconds)
      ..badCertificateCallback = (cert, host, port) {
        // Certificate pinning
        if (config.pinnedCertificateHashes.isEmpty) return false;
        final certHash = sha256Hash(cert.pem);
        return config.pinnedCertificateHashes.contains(certHash);
      };

    return IOClient(httpClient);
  }

  String sha256Hash(String input) {
    return _secureStorage.computeHmac(input, 'cert-pin');
  }

  String get _baseUrl => config.isProduction
      ? 'https://api.yourpaymentserver.com/v1'
      : 'https://sandbox-api.yourpaymentserver.com/v1';

  Future<Map<String, String>> _getHeaders() async {
    final sessionToken = await _secureStorage.getSessionToken();
    return {
      'Content-Type': 'application/json',
      'Authorization': 'Bearer ${sessionToken ?? ''}',
      'X-Idempotency-Key': _secureStorage.generateIdempotencyKey(),
      'X-Client-Version': '1.0.0',
      'X-Platform': Platform.operatingSystem,
    };
  }

  // Create payment intent on server
  Future<PaymentResult> createPaymentIntent(PaymentRequest request) async {
    return _executeWithRetry(() async {
      final headers = await _getHeaders();
      headers['X-Idempotency-Key'] = request.idempotencyKey;

      final response = await _httpClient
          .post(
            Uri.parse('$_baseUrl/payments/intent'),
            headers: headers,
            body: jsonEncode(request.toJson()),
          )
          .timeout(Duration(seconds: config.transactionTimeoutSeconds));

      return _handleResponse(response, request);
    });
  }

  // Confirm payment with 3DS/SCA
  Future<PaymentResult> confirmPayment(
    String paymentIntentId,
    String clientSecret,
  ) async {
    return _executeWithRetry(() async {
      final headers = await _getHeaders();

      final response = await _httpClient
          .post(
            Uri.parse('$_baseUrl/payments/$paymentIntentId/confirm'),
            headers: headers,
            body: jsonEncode({'client_secret': clientSecret}),
          )
          .timeout(Duration(seconds: config.transactionTimeoutSeconds));

      if (response.statusCode == 200) {
        final json = jsonDecode(response.body) as Map<String, dynamic>;
        return PaymentResult.fromJson(json);
      }

      throw PaymentException(
        code: 'CONFIRM_FAILED',
        message: 'Payment confirmation failed: ${response.statusCode}',
      );
    });
  }

  // Process refund
  Future<PaymentResult> processRefund(
    String transactionId,
    PaymentAmount amount,
  ) async {
    final headers = await _getHeaders();

    final response = await _httpClient
        .post(
          Uri.parse('$_baseUrl/payments/$transactionId/refund'),
          headers: headers,
          body: jsonEncode(amount.toJson()),
        )
        .timeout(Duration(seconds: config.transactionTimeoutSeconds));

    if (response.statusCode == 200) {
      final json = jsonDecode(response.body) as Map<String, dynamic>;
      return PaymentResult.fromJson(json);
    }

    throw PaymentException(
      code: 'REFUND_FAILED',
      message: 'Refund processing failed: ${response.statusCode}',
    );
  }

  // Tokenize card via payment gateway (PCI compliant - card data never touches our server)
  Future<PaymentCard> tokenizeCard({
    required String cardNumber,
    required int expiryMonth,
    required int expiryYear,
    required String cvc,
    String? cardholderName,
  }) async {
    // This calls Stripe's API directly from client for PCI compliance
    // Card data is sent directly to Stripe, never to our backend
    final response = await _httpClient.post(
      Uri.parse('https://api.stripe.com/v1/tokens'),
      headers: {
        'Authorization': 'Bearer ${config.stripePublishableKey}',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {
        'card[number]': cardNumber,
        'card[exp_month]': expiryMonth.toString(),
        'card[exp_year]': expiryYear.toString(),
        'card[cvc]': cvc,
        if (cardholderName != null) 'card[name]': cardholderName,
      },
    );

    if (response.statusCode == 200) {
      final json = jsonDecode(response.body) as Map<String, dynamic>;
      final cardData = json['card'] as Map<String, dynamic>;

      return PaymentCard(
        tokenizedId: json['id'] as String,
        network: _parseCardNetwork(cardData['brand'] as String?),
        last4: cardData['last4'] as String,
        expiryMonth: expiryMonth,
        expiryYear: expiryYear,
        cardholderName: cardholderName,
        fingerprint: cardData['fingerprint'] as String?,
      );
    }

    final error = jsonDecode(response.body);
    throw PaymentException(
      code: 'TOKENIZATION_FAILED',
      message: error['error']?['message'] ?? 'Card tokenization failed',
    );
  }

  // Validate payment receipt (server-side verification for IAP)
  Future<bool> validateReceipt({
    required String receiptData,
    required String productId,
    required String platform,
  }) async {
    final headers = await _getHeaders();

    final response = await _httpClient.post(
      Uri.parse('$_baseUrl/purchases/validate'),
      headers: headers,
      body: jsonEncode({
        'receipt_data': receiptData,
        'product_id': productId,
        'platform': platform,
      }),
    );

    if (response.statusCode == 200) {
      final json = jsonDecode(response.body) as Map<String, dynamic>;
      return json['valid'] as bool? ?? false;
    }

    return false;
  }

  PaymentResult _handleResponse(http.Response response, PaymentRequest request) {
    if (response.statusCode == 200 || response.statusCode == 201) {
      final json = jsonDecode(response.body) as Map<String, dynamic>;
      return PaymentResult.fromJson(json);
    }

    if (response.statusCode == 402) {
      final json = jsonDecode(response.body) as Map<String, dynamic>;
      return PaymentResult.failure(
        errorCode: json['error_code'] as String? ?? 'PAYMENT_DECLINED',
        errorMessage: json['error_message'] as String? ?? 'Payment was declined',
        amount: request.amount,
        method: request.method,
      );
    }

    if (response.statusCode == 429) {
      throw const PaymentException(
        code: 'RATE_LIMITED',
        message: 'Too many payment requests. Please try again later.',
      );
    }

    throw PaymentException(
      code: 'GATEWAY_ERROR',
      message: 'Payment gateway error: ${response.statusCode}',
    );
  }

  Future<T> _executeWithRetry<T>(
    Future<T> Function() operation, {
    int? maxRetries,
  }) async {
    final retries = maxRetries ?? config.maxRetryAttempts;
    PaymentException? lastException;

    for (var attempt = 0; attempt <= retries; attempt++) {
      try {
        return await operation();
      } on PaymentException catch (e) {
        lastException = e;
        // Don't retry on client errors
        if (e.code == 'PAYMENT_DECLINED' ||
            e.code == 'TOKENIZATION_FAILED' ||
            e.code == 'RATE_LIMITED') {
          rethrow;
        }
        if (attempt < retries) {
          await Future.delayed(Duration(milliseconds: 500 * (attempt + 1)));
        }
      } on TimeoutException {
        lastException = const PaymentException(
          code: 'TIMEOUT',
          message: 'Payment request timed out',
        );
        if (attempt < retries) {
          await Future.delayed(Duration(milliseconds: 500 * (attempt + 1)));
        }
      } on SocketException {
        lastException = const PaymentException(
          code: 'NETWORK_ERROR',
          message: 'Network connection error',
        );
        if (attempt < retries) {
          await Future.delayed(Duration(milliseconds: 500 * (attempt + 1)));
        }
      }
    }

    throw lastException ??
        const PaymentException(
          code: 'UNKNOWN',
          message: 'Payment processing failed',
        );
  }

  CardNetwork _parseCardNetwork(String? brand) {
    switch (brand?.toLowerCase()) {
      case 'visa':
        return CardNetwork.visa;
      case 'mastercard':
        return CardNetwork.mastercard;
      case 'amex':
      case 'american express':
        return CardNetwork.amex;
      case 'discover':
        return CardNetwork.discover;
      default:
        return CardNetwork.unknown;
    }
  }

  void dispose() {
    _httpClient.close();
  }
}

// lib/payment_module/services/in_app_purchase_service.dart

import 'dart:async';
import 'dart:io';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';
import '../models/payment_models.dart';
import 'payment_gateway_service.dart';

class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentGatewayService _gatewayService;
  StreamSubscription<List<PurchaseDetails>>? _subscription;

  final _purchaseController = StreamController<PaymentResult>.broadcast();
  Stream<PaymentResult> get purchaseStream => _purchaseController.stream;

  final Set<String> _pendingPurchases = {};

  InAppPurchaseService({required PaymentGatewayService gatewayService})
      : _gatewayService = gatewayService;

  Future<void> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) {
      throw const PaymentException(
        code: 'IAP_UNAVAILABLE',
        message: 'In-app purchases are not available on this device',
      );
    }

    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onError: (error) {
        _purchaseController.addError(
          PaymentException(
            code: 'IAP_STREAM_ERROR',
            message: error.toString(),
          ),
        );
      },
    );

    // Enable pending purchases on Android
    if (Platform.isAndroid) {
      final androidPlatform =
          _iap.getPlatformAddition<InAppPurchaseAndroidPlatformAddition>();
      await androidPlatform.enablePendingPurchases();
    }
  }

  Future<List<InAppProduct>> getProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);

    if (response.error != null) {
      throw PaymentException(
        code: 'PRODUCT_QUERY_FAILED',
        message: response.error!.message,
      );
    }

    return response.productDetails.map((pd) {
      return InAppProduct(
        productId: pd.id,
        title: pd.title,
        description: pd.description,
        price: PaymentAmount(
          amountInCents: (pd.rawPrice * 100).round(),
          currency: pd.currencyCode,
        ),
      );
    }).toList();
  }

  Future<void> purchaseProduct(InAppProduct product) async {
    if (_pendingPurchases.contains(product.productId)) {
      throw const PaymentException(
        code: 'DUPLICATE_PURCHASE',
        message: 'This purchase is already being processed',
      );
    }

    _pendingPurchases.add(product.productId);

    final productDetails = (await _iap.queryProductDetails({product.productId}))
        .productDetails;

    if (productDetails.isEmpty) {
      _pendingPurchases.remove(product.productId);
      throw const PaymentException(
        code: 'PRODUCT_NOT_FOUND',
        message: 'Product not found in store',
      );
    }

    final purchaseParam = PurchaseParam(
      productDetails: productDetails.first,
    );

    try {
      if (product.isSubscription) {
        await _iap.buyNonConsumable(purchaseParam: purchaseParam);
      } else {
        await _iap.buyConsumable(purchaseParam: purchaseParam);
      }
    } catch (e) {
      _pendingPurchases.remove(product.productId);
      rethrow;
    }
  }

  Future<void> restorePurchases() async {
    await _iap.restorePurchases();
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      _pendingPurchases.remove(purchase.productID);

      switch (purchase.status) {
        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          final verified = await _verifyPurchase(purchase);
          if (verified) {
            _purchaseController.add(PaymentResult(
              transactionId: purchase.purchaseID ?? '',
              status: PaymentStatus.completed,
              amount: const PaymentAmount(amountInCents: 0), // Resolved from product
              method: PaymentMethod.inAppPurchase,
              timestamp: DateTime.now(),
              gatewayResponse: {
                'product_id': purchase.productID,
                'purchase_id': purchase.purchaseID,
              },
            ));
          } else {
            _purchaseController.add(PaymentResult.failure(
              errorCode: 'VERIFICATION_FAILED',
              errorMessage: 'Purchase verification failed',
              amount: const PaymentAmount(amountInCents: 0),
              method: PaymentMethod.inAppPurchase,
            ));
          }
          break;

        case PurchaseStatus.error:
          _purchaseController.add(PaymentResult.failure(
            errorCode: 'IAP_ERROR',
            errorMessage: purchase.error?.message ?? 'Purchase failed',
            amount: const PaymentAmount(amountInCents: 0),
            method: PaymentMethod.inAppPurchase,
          ));
          break;

        case PurchaseStatus.canceled:
          _purchaseController.add(PaymentResult(
            transactionId: purchase.purchaseID ?? '',
            status: PaymentStatus.cancelled,
            amount: const PaymentAmount(amountInCents: 0),
            method: PaymentMethod.inAppPurchase,
            timestamp: DateTime.now(),
          ));
          break;

        case PurchaseStatus.pending:
          _purchaseController.add(PaymentResult(
            transactionId: purchase.purchaseID ?? '',
            status: PaymentStatus.pending,
            amount: const PaymentAmount(amountInCents: 0),
            method: PaymentMethod.inAppPurchase,
            timestamp: DateTime.now(),
          ));
          break;
      }

      // Complete pending purchases
      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    }
  }

  Future<bool> _verifyPurchase(PurchaseDetails purchase) async {
    String receiptData;

    if (Platform.isIOS) {
      final skPurchase = purchase as AppStorePurchaseDetails;
      receiptData = skPurchase.verificationData.serverVerificationData;
    } else {
      receiptData = purchase.verificationData.serverVerificationData;
    }

    return _gatewayService.validateReceipt(
      receiptData: receiptData,
      productId: purchase.productID,
      platform: Platform.operatingSystem,
    );
  }

  void dispose() {
    _subscription?.cancel();
    _purchaseController.close();
  }
}

// lib/payment_module/services/payment_service.dart

import 'dart:async';
import 'package:flutter/foundation.dart';
import '../config/payment_config.dart';
import '../models/payment_models.dart';
import 'device_integrity_service.dart';
import 'payment_gateway_service.dart';
import 'secure_storage_service.dart';
import 'in_app_purchase_service.dart';

class PaymentService extends ChangeNotifier {
  final PaymentConfig config;
  final DeviceIntegrityService _integrityService;
  final PaymentGatewayService _gatewayService;
  final SecureStorageService _secureStorage;
  late final InAppPurchaseService _iapService;

  bool _isInitialized = false;
  bool _isProcessing = false;
  DeviceIntegrityResult? _lastIntegrityCheck;
  PaymentResult? _lastResult;
  List<PaymentCard> _savedCards = [];

  bool get isInitialized => _isInitialized;
  bool get isProcessing => _isProcessing;
  DeviceIntegrityResult? get lastIntegrityCheck => _lastIntegrityCheck;
  PaymentResult? get lastResult => _lastResult;
  List<PaymentCard> get savedCards => List.unmodifiable(_savedCards);

  Stream<PaymentResult> get iapPurchaseStream => _iapService.purchaseStream;

  PaymentService({
    required this.config,
    DeviceIntegrityService? integrityService,
    SecureStorageService? secureStorage,
  })  : _integrityService = integrityService ?? DeviceIntegrityService(),
        _secureStorage = secureStorage ?? SecureStorageService(),
        _gatewayService = PaymentGatewayService(
          config: config,
          secureStorage: secureStorage ?? SecureStorageService(),
        ) {
    _iapService = InAppPurchaseService(gatewayService: _gatewayService);
  }

  Future<void> initialize() async {
    if (_isInitialized) return;

    // Perform device integrity check
    if (config.enableDeviceIntegrity) {
      _lastIntegrityCheck = await _integrityService.checkIntegrity();

      if (!_lastIntegrityCheck!.isSecure && config.isProduction) {
        throw SecurityException(
          code: 'DEVICE_COMPROMISED',
          message: _getIntegrityErrorMessage(_lastIntegrityCheck!),
        );
      }
    }

    // Initialize IAP
    await _iapService.initialize();

    // Load saved cards
    _savedCards = await _secureStorage.getSavedCards();

    _isInitialized = true;
    notifyListeners();
  }

  String _getIntegrityErrorMessage(DeviceIntegrityResult result) {
    final issues = <String>[];
    if (result.isRooted) issues.add('rooted/jailbroken device');
    if (result.isEmulator) issues.add('emulator detected');
    if (result.isDebuggerAttached) issues.add('debugger attached');
    if (result.isTampered) issues.add('app tampering detected');
    return 'Device integrity check failed: ${issues.join(', ')}';
  }

  // Process card payment
  Future<PaymentResult> processCardPayment({
    required PaymentAmount amount,
    required PaymentCard card,
    String? description,
    Map<String, String> metadata = const {},
  }) async {
    _ensureInitialized();
    await _ensureDeviceSecure();

    if (card.isExpired) {
      throw const PaymentException(
        code: 'CARD_EXPIRED',
        message: 'The selected card has expired',
      );
    }

    _setProcessing(true);

    try {
      final request = PaymentRequest(
        idempotencyKey: _secureStorage.generateIdempotencyKey(),
        amount: amount,
        method: PaymentMethod.creditCard,
        card: card,
        description: description,
        metadata: {
          ...metadata,
          'device_fingerprint':
              await _integrityService.generateDeviceFingerprint(),
        },
      );

      final result = await _gatewayService.createPaymentIntent(request);

      // Handle 3DS/SCA if required
      if (result.requiresAction && result.clientSecret != null) {
        _lastResult = result;
        notifyListeners();
        return result; // Caller must handle 3DS flow
      }

      await _secureStorage.logTransaction(result);
      _lastResult = result;
      return result;
    } on PaymentException {
      rethrow;
    } catch (e, st) {
      throw PaymentException(
        code: 'PROCESSING_ERROR',
        message: 'Payment processing failed: ${e.toString()}',
        originalError: e,
        stackTrace: st,
      );
    } finally {
      _setProcessing(false);
    }
  }

  // Confirm 3DS/SCA payment
  Future<PaymentResult> confirm3DSPayment(
    String paymentIntentId,
    String clientSecret,
  ) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      final result = await _gatewayService.confirmPayment(
        paymentIntentId,
        clientSecret,
      );

      await _secureStorage.logTransaction(result);
      _lastResult = result;
      return result;
    } finally {
      _setProcessing(false);
    }
  }

  // Process Apple Pay / Google Pay
  Future<PaymentResult> processWalletPayment({
    required PaymentAmount amount,
    required PaymentMethod walletType,
    String? description,
    Map<String, String> metadata = const {},
  }) async {
    _ensureInitialized();
    await _ensureDeviceSecure();

    if (walletType != PaymentMethod.applePay &&
        walletType != PaymentMethod.googlePay) {
      throw const PaymentException(
        code: 'INVALID_WALLET',
        message: 'Invalid wallet type specified',
      );
    }

    _setProcessing(true);

    try {
      final request = PaymentRequest(
        idempotencyKey: _secureStorage.generateIdempotencyKey(),
        amount: amount,
        method: walletType,
        description: description,
        metadata: {
          ...metadata,
          'device_fingerprint':
              await _integrityService.generateDeviceFingerprint(),
        },
      );

      final result = await _gatewayService.createPaymentIntent(request);
      await _secureStorage.logTransaction(result);
      _lastResult = result;
      return result;
    } finally {
      _setProcessing(false);
    }
  }

  // Tokenize and save a new card
  Future<PaymentCard> addCard({
    required String cardNumber,
    required int expiryMonth,
    required int expiryYear,
    required String cvc,
    String? cardholderName,
  }) async {
    _ensureInitialized();

    // Basic validation
    _validateCardInput(cardNumber, expiryMonth, expiryYear, cvc);

    final card = await _gatewayService.tokenizeCard(
      cardNumber: cardNumber,
      expiryMonth: expiryMonth,
      expiryYear: expiryYear,
      cvc: cvc,
      cardholderName: cardholderName,
    );

    await _secureStorage.saveCard(card);
    _savedCards = await _secureStorage.getSavedCards();
    notifyListeners();

    return card;
  }

  Future<void> removeCard(String tokenizedId) async {
    await _secureStorage.removeCard(tokenizedId);
    _savedCards = await _secureStorage.getSavedCards();
    notifyListeners();
  }

  // In-app purchase
  Future<List<InAppProduct>> getAvailableProducts(
      Set<String> productIds) async {
    _ensureInitialized();
    return _iapService.getProducts(productIds);
  }

  Future<void> purchaseProduct(InAppProduct product) async {
    _ensureInitialized();
    await _ensureDeviceSecure();
    await _iapService.purchaseProduct(product);
  }

  Future<void> restorePurchases() async {
    _ensureInitialized();
    await _iapService.restorePurchases();
  }

  // Process refund
  Future<PaymentResult> processRefund(
    String transactionId,
    PaymentAmount amount,
  ) async {
    _ensureInitialized();
    _setProcessing(true);

    try {
      final result = await _gatewayService.processRefund(transactionId, amount);
      await _secureStorage.logTransaction(result);
      _lastResult = result;
      return result;
    } finally {
      _setProcessing(false);
    }
  }

  // Re-check device integrity
  Future<DeviceIntegrityResult> recheckIntegrity() async {
    _lastIntegrityCheck = await _integrityService.checkIntegrity();
    notifyListeners();
    return _lastIntegrityCheck!;
  }

  void _ensureInitialized() {
    if (!_isInitialized) {
      throw const PaymentException(
        code: 'NOT_INITIALIZED',
        message: 'PaymentService must be initialized before use',
      );
    }
  }

  Future<void> _ensureDeviceSecure() async {
    if (!config.enableDeviceIntegrity) return;

    // Re-check if last check is older than 5 minutes
    if (_lastIntegrityCheck == null ||
        DateTime.now().difference(_lastIntegrityCheck!.checkedAt).inMinutes >
            5) {
      _lastIntegrityCheck = await _integrityService.checkIntegrity();
    }

    if (!_lastIntegrityCheck!.isSecure && config.isProduction) {
      throw SecurityException(
        code: 'DEVICE_COMPROMISED',
        message: _getIntegrityErrorMessage(_lastIntegrityCheck!),
      );
    }
  }

  void _validateCardInput(
    String cardNumber,
    int expiryMonth,
    int expiryYear,
    String cvc,
  ) {
    final cleanNumber = cardNumber.replaceAll(RegExp(r'\s|-'), '');

    if (cleanNumber.length < 13 || cleanNumber.length > 19) {
      throw const PaymentException(
        code: 'INVALID_CARD_NUMBER',
        message: 'Invalid card number length',
      );
    }

    if (!_luhnCheck(cleanNumber)) {
      throw const PaymentException(
        code: 'INVALID_CARD_NUMBER',
        message: 'Invalid card number',
      );
    }

    if (expiryMonth < 1 || expiryMonth > 12) {
      throw const PaymentException(
        code: 'INVALID_EXPIRY',
        message: 'Invalid expiry month',
      );
    }

    final now = DateTime.now();
    if (DateTime(expiryYear, expiryMonth + 1).isBefore(now)) {
      throw const PaymentException(
        code: 'CARD_EXPIRED',
        message: 'Card has expired',
      );
    }

    if (cvc.length < 3 || cvc.length > 4) {
      throw const PaymentException(
        code: 'INVALID_CVC',
        message: 'Invalid CVC',
      );
    }
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;

    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);

      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      alternate = !alternate;
    }

    return sum % 10 == 0;
  }

  void _setProcessing(bool value) {
    _isProcessing = value;
    notifyListeners();
  }

  @override
  void dispose() {
    _iapService.dispose();
    _gatewayService.dispose();
    super.dispose();
  }
}

// lib/payment_module/widgets/payment_sheet.dart

import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import '../models/payment_models.dart';
import '../services/payment_service.dart';

class PaymentSheet extends StatefulWidget {
  final PaymentService paymentService;
  final PaymentAmount amount;
  final String? description;
  final bool showWalletOptions;
  final bool showSavedCards;
  final void Function(PaymentResult result)? onPaymentComplete;
  final void Function(PaymentException error)? onPaymentError;

  const PaymentSheet({
    super.key,
    required this.paymentService,
    required this.amount,
    this.description,
    this.showWalletOptions = true,
    this.showSavedCards = true,
    this.onPaymentComplete,
    this.onPaymentError,
  });

  static Future<PaymentResult?> show(
    BuildContext context, {
    required PaymentService paymentService,
    required PaymentAmount amount,
    String? description,
    bool showWalletOptions = true,
    bool showSavedCards = true,
  }) {
    return showModalBottomSheet<PaymentResult>(
      context: context,
      isScrollControlled: true,
      backgroundColor: Colors.transparent,
      builder: (context) => PaymentSheet(
        paymentService: paymentService,
        amount: amount,
        description: description,
        showWalletOptions: showWalletOptions,
        showSavedCards: showSavedCards,
      ),
    );
  }

  @override
  State<PaymentSheet> createState() => _PaymentSheetState();
}

class _PaymentSheetState extends State<PaymentSheet> {
  final _formKey = GlobalKey<FormState>();
  final _cardNumberController = TextEditingController();
  final _expiryController = TextEditingController();
  final _cvcController = TextEditingController();
  final _nameController = TextEditingController();

  bool _isProcessing = false;
  bool _saveCard = false;
  PaymentCard? _selectedSavedCard;
  String? _errorMessage;

  @override
  void dispose() {
    // Securely clear sensitive data from controllers
    _cardNumberController.clear();
    _expiryController.clear();
    _cvcController.clear();
    _nameController.clear();
    _cardNumberController.dispose();
    _expiryController.dispose();
    _cvcController.dispose();
    _nameController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final bottomPadding = MediaQuery.of(context).viewInsets.bottom;

    return Container(
      decoration: BoxDecoration(
        color: theme.scaffoldBackgroundColor,
        borderRadius: const BorderRadius.vertical(top: Radius.circular(20)),
      ),
      padding: EdgeInsets.only(bottom: bottomPadding),
      child: SingleChildScrollView(
        child: Padding(
          padding: const EdgeInsets.all(24),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              _buildHandle(),
              const SizedBox(height: 16),
              _buildHeader(theme),
              const SizedBox(height: 24),
              if (widget.showWalletOptions) ...[
                _buildWalletOptions(theme),
                _buildDivider(theme),
              ],
              if (widget.showSavedCards &&
                  widget.paymentService.savedCards.isNotEmpty) ...[
                _buildSavedCards(theme),
                _buildDivider(theme),
              ],
              _buildCardForm(theme),
              if (_errorMessage != null) ...[
                const SizedBox(height: 12),
                _buildErrorMessage(theme),
              ],
              const SizedBox(height: 24),
              _buildPayButton(theme),
              const SizedBox(height: 16),
              _buildSecurityBadge(theme),
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildHandle() {
    return Center(
      child: Container(
        width: 40,
        height: 4,
        decoration: BoxDecoration(
          color: Colors.grey[300],
          borderRadius: BorderRadius.circular(2),
        ),
      ),
    );
  }

  Widget _buildHeader(ThemeData theme) {
    return Column(
      children: [
        Text(
          'Payment',
          style: theme.textTheme.headlineSmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
        ),
        const SizedBox(height: 8),
        Text(
          widget.amount.displayAmount,
          style: theme.textTheme.headlineMedium?.copyWith(
            fontWeight: FontWeight.w700,
            color: theme.primaryColor,
          ),
        ),
        if (widget.description != null) ...[
          const SizedBox(height: 4),
          Text(
            widget.description!,
            style: theme.textTheme.bodyMedium?.copyWith(
              color: Colors.grey[600],
            ),
          ),
        ],
      ],
    );
  }

  Widget _buildWalletOptions(ThemeData theme) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        _WalletButton(
          icon: Icons.apple,
          label: 'Apple Pay',
          onPressed: _isProcessing ? null : () => _processWalletPayment(PaymentMethod.applePay),
        ),
        const SizedBox(height: 8),
        _WalletButton(
          icon: Icons.g_mobiledata,
          label: 'Google Pay',
          onPressed: _isProcessing ? null : () => _processWalletPayment(PaymentMethod.googlePay),
        ),
      ],
    );
  }

  Widget _buildSavedCards(ThemeData theme) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Text(
          'Saved Cards',
          style: theme.textTheme.titleSmall?.copyWith(
            fontWeight: FontWeight.w600,
          ),
        ),
        const SizedBox(height: 8),
        ...widget.paymentService.savedCards.map((card) {
          final isSelected = _selectedSavedCard?.tokenizedId == card.tokenizedId;
          return _SavedCardTile(
            card: card,
            isSelected: isSelected,
            onTap: () {
              setState(() {
                _selectedSavedCard = isSelected ? null : card;
                _errorMessage = null;
              });
            },
          );
        }),
      ],
    );
  }

